<?php
namespace App\Controllers;
use App\Core\Auth; use App\Core\Database; use App\Core\View; use App\Services\AuditService;
final class ApprovalController {
 public function index():void{Auth::requireLogin();$pdo=Database::connection();$rows=$pdo->query("SELECT a.*,d.original_name,d.document_type,r.name requester,u.name assignee FROM document_approvals a JOIN documents d ON d.id=a.document_id LEFT JOIN users r ON r.id=a.requested_by LEFT JOIN users u ON u.id=a.assigned_to ORDER BY a.requested_at DESC")->fetchAll();View::render('portal/approvals/index',['title'=>'Document Approvals','rows'=>$rows,'documents'=>$pdo->query('SELECT id,original_name FROM documents ORDER BY created_at DESC LIMIT 100')->fetchAll(),'users'=>$pdo->query("SELECT id,name FROM users WHERE status='active' ORDER BY name")->fetchAll()],'portal');}
 public function store():void{Auth::requireRole('owner','office');verify_csrf();$pdo=Database::connection();$pdo->prepare('INSERT INTO document_approvals(document_id,requested_by,assigned_to,comments) VALUES(?,?,?,?)')->execute([(int)$_POST['document_id'],Auth::id(),($_POST['assigned_to']??'')?:null,trim($_POST['comments']??'')]);AuditService::log('document.approval_requested','document',(int)$_POST['document_id']);flash('success','Approval requested.');redirect('/portal/approvals');}
 public function decide(int $id):void{Auth::requireRole('owner','office','administrator');verify_csrf();$status=in_array($_POST['status']??'', ['approved','rejected','cancelled'],true)?$_POST['status']:'rejected';Database::connection()->prepare('UPDATE document_approvals SET status=?,comments=?,decided_at=NOW() WHERE id=?')->execute([$status,trim($_POST['comments']??''),$id]);AuditService::log('document.approval_'.$status,'document_approval',$id);flash('success','Approval updated.');redirect('/portal/approvals');}
}
